				count += C[j] - M[i];

			i++;

			j++;

		}

		return ③;

	}

	void sort(int a[], int l, int r) {

		int i = l, j = r, x = a[(l + r) / 2], y;

		while (i <= j) {

			while (a[i] < x) i++;

			while (a[j] > x) j--;

			if (i <= j) {

				y = a[i]; a[i] = a[j]; a[j] = y;

				i++; j--;

			}

		}

	if (i < r) sort(a, i, r);

	if (l < j) sort(a, l, j);

	}

