	#include <algorithm>

	#include <iostream>

	#include <queue>

	#include <vector>

	using namespace std;

	const long long INF = 1e18;

	struct Edge {

	    int to;

	    int weight;

	};

	struct State {

	    long long dist;

	    int u;

	    int used_freebie; // 0 for not used, 1 for used

	    bool operator>(const State &other) const {

	        return dist > other.dist;

	    }

	};

	int main() {

	    int n, m, s, t;

	    cin >> n >> m >> s >> t;

	    vector<vector<Edge>> adj(n + 1);

	    for (int i = 0; i < m; ++i) {

	        int u, v, w;

	        cin >> u >> v >> w;

	        adj[u].push_back({v, w});

	        adj[v].push_back({u, w});

	    }

	    vector<vector<long long>> d(n + 1, vector<long long>(2, INF));

	    priority_queue<State, vector<State>, greater<State>> pq;

	    d[s][0] = 0;

	    pq.push({0, s, __①__});

	    while (!pq.empty()) {

	        State current = pq.top();

	        pq.pop();

	        long long dist = current.dist;

	        int u = current.u;

	        int used = current.used_freebie;

	        if (dist > __②__) {

	            continue;

	        }

	        for (const auto &edge : adj[u]) {

	            int v = edge.to;

	            int w = edge.weight;

	            if (d[u][used] + w < __③__) {

	                __③__ = d[u][used] + w;

	                pq.push({__③__, v, used});

	            }

	            if (used == 0) {

	                if (__④__ < d[v][1]) {

	                    d[v][1] = d[u][used];

	                    pq.push({d[v][1], v, 1});

	                }

	            }

	        }

	    }

	    cout << __⑤__ << endl;

	    return 0;

	}
